/// <reference types="node" />
import { EventEmitter } from 'events';
/**
 * Statically check a `.flow` file and its dependencies for inconsistencies and missing resources.
 * ```
 * import {MimFixer} from 'jibo-dev';
 * var fixer = new MimFixer(path.join(__dirname, 'mims'));
 * linter.run();
 * console.log(linter.getErrorReport());
 * ```
 * @class MimFixer
 */
export default class MimFixer extends EventEmitter {
    target: string;
    verbose: boolean;
    constructor();
    /**
     * Processes a folder of .mim files or a single file.
     * @method MimFixer#run
     * @param {string} target Path to the skill's folder to fix mims found within, or path to a specific .mim file to run on.
     * @param {boolean} [verbose=false] If extended information should be logged.
     */
    run(target: string, verbose?: boolean): void;
    private processMim(filename);
}
